proof_block:
// `SingleDelivery::send_single_message(pre, post, m, dst, sm, params)` is a
// deterministic open spec: `let new_seqno = ack_state_lookup(dst,
// pre.send_state).num_packets_acked + ack_state_lookup(dst,
// pre.send_state).un_acked.len() + 1; if new_seqno > params.max_seqno {
// post == pre && sm is None } else { sm == Some(SingleMessage::Message{...})
// && post == SingleDelivery{ send_state: pre.send_state.insert(dst, ...), ..pre } }`.
//
// Hence both `sm@` (i.e. `Some(rN->Some_0@)` vs `None`) and `post@` are
// uniquely determined by `(pre_self_@, m@, dst@, params)`.  z3 returns
// `unknown` because the two ensures-conjuncts (for `r1` and `r2`) unfold
// `send_single_message` on disjoint `(post,sm)` chains and never align the
// resulting if/else case-split.  We close the gap by re-stating each
// possibility in implication form — every assert is unconditionally
// provable by unfolding the open spec on both sides and using the
// `#[verifier::ext_equal]` annotation on `SingleDelivery`.

// (A) A Some/None mismatch across the two runs is contradictory: a `Some`
//     witness forces `new_seqno <= max_seqno`, a `None` witness forces
//     `new_seqno > max_seqno`.
assert(
    (r1 is Some) && (r2 is None)
    && SingleDelivery::send_single_message(pre_self_@, post1_self_@, m@, dst@, Some(r1->Some_0@), AbstractParameters::static_params())
    && SingleDelivery::send_single_message(pre_self_@, post2_self_@, m@, dst@, None, AbstractParameters::static_params())
  ==> false
);
assert(
    (r1 is None) && (r2 is Some)
    && SingleDelivery::send_single_message(pre_self_@, post1_self_@, m@, dst@, None, AbstractParameters::static_params())
    && SingleDelivery::send_single_message(pre_self_@, post2_self_@, m@, dst@, Some(r2->Some_0@), AbstractParameters::static_params())
  ==> false
);

// (B) Both runs `Some`: both land in the else-branch, pinning the
//     `SingleMessage::Message` witness and the `SingleDelivery` view to the
//     same `pre_self_@`-dependent expressions.
assert(
    (r1 is Some) && (r2 is Some)
    && SingleDelivery::send_single_message(pre_self_@, post1_self_@, m@, dst@, Some(r1->Some_0@), AbstractParameters::static_params())
    && SingleDelivery::send_single_message(pre_self_@, post2_self_@, m@, dst@, Some(r2->Some_0@), AbstractParameters::static_params())
  ==> r1->Some_0@ == r2->Some_0@ && post1_self_@ == post2_self_@
);

// (C) Both runs `None`: both land in the then-branch, so `post1_self_@ ==
//     pre_self_@ == post2_self_@`.
assert(
    SingleDelivery::send_single_message(pre_self_@, post1_self_@, m@, dst@, None, AbstractParameters::static_params())
    && SingleDelivery::send_single_message(pre_self_@, post2_self_@, m@, dst@, None, AbstractParameters::static_params())
  ==> post1_self_@ == post2_self_@
);

// (D) `SingleDelivery<MT>` carries `#[verifier::ext_equal]`, so its `==`
//     unfolds to per-component view equality — bridging
//     `post_self_@ ==` to the projections used by
//     `det_send_single_cmessage_equal`.
assert(
    post1_self_@ == post2_self_@
  ==> post1_self_.receive_state@ == post2_self_.receive_state@
      && post1_self_.send_state@ == post2_self_.send_state@
);
